hooks.command:
node -e "
const fs = require('fs');
const args = process.argv.slice(1);
const toolInput = JSON.parse(process.env.CLAUDE_TOOL_INPUT || '{}');
const file = toolInput.file_path || toolInput.path || '';
const skip = ['.md', '.json', '.env', '.gitignore', '.prettierrc', '.eslintrc'];
const isDoc = skip.some(ext => file.endsWith(ext));
const isSrc = file.includes('/src/') || file.includes('/tests/') || file.includes('/db/');
if (isSrc && !isDoc) {
  console.error('\n📋 RAPPEL DOCUMENTATION\n' +
    'Fichier modifié : ' + file + '\n' +
    '─────────────────────────────────────────\n' +
    'Avant de terminer cette tâche, assure-toi de :\n' +
    '  1. Mettre à jour DEVLOG.md (ajouts, retraits, modifications)\n' +
    '  2. Ajouter/mettre à jour les JSDoc sur les fonctions modifiées\n' +
    '  3. Noter dans docs/future-work.md si tu identifies des améliorations\n' +
    '  4. Mettre à jour .env.example si une variable a changé\n' +
    '  5. Ajouter dans BUGS.md si un bug non bloquant a été identifié\n' +
    '─────────────────────────────────────────');
}
"
